import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const animateLight = () => {
      const svgDoc = document.getElementById("photoautomat-object")?.contentDocument; // ✅ เข้าถึงเอกสารภายใน <object>
      if (svgDoc) {
        const lightElement = svgDoc.getElementById("light"); // ✅ ดึง element "light"
        if (lightElement) {
          lightElement.style.fill =
            lightElement.style.fill === "rgb(231, 229, 213)" // #e7e5d5
              ? "#ffe966"
              : "#e7e5d5";
        }
      }
    };

    const interval = setInterval(animateLight, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      <div className="home-container mt-24">
      <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>
        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>
      {/* ✅ ใช้ <object> เพื่อโหลดไฟล์ SVG แบบ inline */}
      <object
        id="photoautomat-object"
        type="image/svg+xml"
        data="/photoautomat.svg"
        className="photoautomat-svg"
      />

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
      <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
    </div>
    </div>
  );
};

export default Home;
